import {
  createContext,
  forwardRef,
  useCallback,
  useContext,
  useId,
  useRef,
  useState,
} from 'react';
import O9Checkbox from '../Checkbox/Checkbox';

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

export interface CheckboxGroupContextValue {
  size: 'sm' | 'lg';
  isDisabled: boolean;
  isReadOnly: boolean;
  isLoading: boolean;
  name?: string;
  registerCheckbox: (value: string, isChecked: boolean) => void;
  unregisterCheckbox: (value: string) => void;
  onChildChange: (value: string, isChecked: boolean) => void;
}

export const CheckboxGroupContext = createContext<CheckboxGroupContextValue | null>(null);

export function useCheckboxGroup(): CheckboxGroupContextValue | null {
  return useContext(CheckboxGroupContext);
}

// ---------------------------------------------------------------------------
// Props
// ---------------------------------------------------------------------------

export interface O9CheckboxGroupProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange'> {
  label?: string | null;
  hasSelectAll?: boolean;
  orientation?: 'vertical' | 'horizontal';
  labelPosition?: 'top' | 'start';
  size?: 'sm' | 'lg';
  isDisabled?: boolean;
  isReadOnly?: boolean;
  isRequired?: boolean;
  isInvalid?: boolean;
  errorMsg?: string | null;
  isLoading?: boolean;
  name?: string;
  onChange?: (detail: { values: string[]; allChecked: boolean }) => void;
  children?: React.ReactNode;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const O9CheckboxGroup = forwardRef<HTMLDivElement, O9CheckboxGroupProps>(
  function O9CheckboxGroup(
    {
      label = null,
      hasSelectAll = false,
      orientation = 'vertical',
      labelPosition = 'top',
      size = 'lg',
      isDisabled = false,
      isReadOnly = false,
      isRequired = false,
      isInvalid = false,
      errorMsg = null,
      isLoading = false,
      name,
      onChange,
      className,
      children,
      ...rest
    },
    ref
  ) {
    const uid = useId();
    const labelId = `o9ds-cb-grp-lbl-${uid}`;
    const errorId = `o9ds-cb-grp-err-${uid}`;

    // Map of child value → checked state for tracking select-all
    const childStateRef = useRef<Map<string, boolean>>(new Map());
    const [selectAllChecked, setSelectAllChecked] = useState(false);
    const [selectAllIndeterminate, setSelectAllIndeterminate] = useState(false);

    const recomputeSelectAll = useCallback(() => {
      const states = Array.from(childStateRef.current.values());
      if (states.length === 0) {
        setSelectAllChecked(false);
        setSelectAllIndeterminate(false);
        return;
      }
      const checkedCount = states.filter(Boolean).length;
      setSelectAllChecked(checkedCount === states.length);
      setSelectAllIndeterminate(checkedCount > 0 && checkedCount < states.length);
    }, []);

    const registerCheckbox = useCallback(
      (value: string, isChecked: boolean) => {
        childStateRef.current.set(value, isChecked);
        recomputeSelectAll();
      },
      [recomputeSelectAll]
    );

    const unregisterCheckbox = useCallback(
      (value: string) => {
        childStateRef.current.delete(value);
        recomputeSelectAll();
      },
      [recomputeSelectAll]
    );

    const fireOnChange = useCallback(() => {
      if (!onChange) return;
      const entries = Array.from(childStateRef.current.entries());
      const values = entries.filter(([, isChecked]) => isChecked).map(([v]) => v);
      const allChecked = entries.length > 0 && entries.every(([, isChecked]) => isChecked);
      onChange({ values, allChecked });
    }, [onChange]);

    const onChildChange = useCallback(
      (value: string, isChecked: boolean) => {
        childStateRef.current.set(value, isChecked);
        recomputeSelectAll();
        fireOnChange();
      },
      [recomputeSelectAll, fireOnChange]
    );

    function handleSelectAllChange({ isChecked }: { isChecked: boolean }) {
      childStateRef.current.forEach((_, key) => {
        childStateRef.current.set(key, isChecked);
      });
      recomputeSelectAll();
      if (onChange) {
        const entries = Array.from(childStateRef.current.entries());
        const values = entries.filter(([, c]) => c).map(([v]) => v);
        onChange({ values, allChecked: isChecked });
      }
    }

    const contextValue: CheckboxGroupContextValue = {
      size,
      isDisabled,
      isReadOnly,
      isLoading,
      name,
      registerCheckbox,
      unregisterCheckbox,
      onChildChange,
    };

    const showAlert = isInvalid && !!errorMsg;

    const classes = [
      'o9ds-cb-grp',
      `o9ds-cb-grp--${size}`,
      orientation === 'horizontal' && 'o9ds-cb-grp--horizontal',
      labelPosition === 'start' && 'o9ds-cb-grp--label-start',
      isLoading && 'loading',
      isDisabled && 'is-disabled',
      isReadOnly && 'is-readonly',
      isInvalid && 'has-error',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    const labelClasses = [
      'o9ds-form-lbl',
      'o9ds-cb-grp__lbl',
      size === 'sm' && 'o9ds-form-lbl--sm',
      isRequired && 'o9ds-form-lbl--required',
      isDisabled && 'is-disabled',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <CheckboxGroupContext.Provider value={contextValue}>
        <div
          ref={ref}
          className={classes}
          role="group"
          aria-labelledby={label ? labelId : undefined}
          aria-required={isRequired || undefined}
          aria-invalid={isInvalid || undefined}
          aria-describedby={showAlert ? errorId : undefined}
          aria-busy={isLoading || undefined}
          {...rest}
        >
          {label && (
            <span id={labelId} className={labelClasses}>
              {label}
              {isRequired && (
                <span className="o9ds-form-lbl__req" aria-hidden="true">
                  *
                </span>
              )}
            </span>
          )}
          <div className="o9ds-cb-grp__bdy">
            <div
              className="o9ds-cb-grp__items"
              data-o9ds-loading={isLoading ? 'true' : undefined}
            >
              {hasSelectAll && (
                <O9Checkbox
                  label="Select All"
                  isChecked={selectAllChecked}
                  isIndeterminate={selectAllIndeterminate}
                  size={size}
                  isDisabled={isDisabled}
                  isReadOnly={isReadOnly}
                  isLoading={isLoading}
                  onChange={handleSelectAllChange}
                />
              )}
              {children}
            </div>
            {showAlert && (
              <div
                className="o9ds-inline-alert o9ds-inline-alert--error"
                id={errorId}
                role="alert"
              >
                <span className="o9ds-inline-alert__ico" aria-hidden="true" />
                <span className="o9ds-inline-alert__msg">{errorMsg}</span>
              </div>
            )}
          </div>
        </div>
      </CheckboxGroupContext.Provider>
    );
  }
);

export default O9CheckboxGroup;
